/*
 * LSB Image Steganography in C
 * Hides text messages in BMP images using Least Significant Bit modification
 * Compile: gcc steganography.c -o steganography
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

#pragma pack(push, 1)
// BMP File Header (14 bytes)
typedef struct {
    uint16_t bfType;      // 'BM' signature
    uint32_t bfSize;      // File size
    uint16_t bfReserved1;
    uint16_t bfReserved2;
    uint32_t bfOffBits;   // Offset to pixel data
} BITMAPFILEHEADER;

// BMP DIB Header (40 bytes for BITMAPINFOHEADER)
typedef struct {
    uint32_t biSize;          // Header size
    int32_t  biWidth;         // Image width
    int32_t  biHeight;        // Image height
    uint16_t biPlanes;        // Color planes
    uint16_t biBitCount;      // Bits per pixel (24 for RGB)
    uint32_t biCompression;   // Compression type
    uint32_t biSizeImage;     // Image size
    int32_t  biXPelsPerMeter;
    int32_t  biYPelsPerMeter;
    uint32_t biClrUsed;
    uint32_t biClrImportant;
} BITMAPINFOHEADER;
#pragma pack(pop)

// Convert a character to 8-bit binary string
void char_to_binary(char c, char *binary) {
    for (int i = 7; i >= 0; i--) {
        binary[7 - i] = (c & (1 << i)) ? '1' : '0';
    }
    binary[8] = '\0';
}

// Convert binary string to character
char binary_to_char(const char *binary) {
    char c = 0;
    for (int i = 0; i < 8; i++) {
        if (binary[i] == '1') {
            c |= (1 << (7 - i));
        }
    }
    return c;
}

// Embed message into BMP file
int embed_message(const char *image_path, const char *message, const char *output_path) {
    FILE *fp = fopen(image_path, "rb");
    if (!fp) {
        printf("Error: Cannot open image file\n");
        return -1;
    }

    // Read BMP headers
    BITMAPFILEHEADER fileHeader;
    BITMAPINFOHEADER infoHeader;

    fread(&fileHeader, sizeof(BITMAPFILEHEADER), 1, fp);
    fread(&infoHeader, sizeof(BITMAPINFOHEADER), 1, fp);

    // Validate BMP format
    if (fileHeader.bfType != 0x4D42) {  // 'MB' in little-endian
        printf("Error: Not a valid BMP file\n");
        fclose(fp);
        return -1;
    }

    int width = infoHeader.biWidth;
    int height = abs(infoHeader.biHeight);
    int row_size = ((width * 3 + 3) / 4) * 4;  // BMP rows are padded to 4 bytes
    int total_pixels = width * height;

    printf("Image: %dx%d, Total pixels: %d\n", width, height, total_pixels);

    // Calculate message bits
    int msg_len = strlen(message);
    int total_bits = (msg_len + 1) * 8;  // +1 for null terminator
    int required_pixels = (total_bits + 2) / 3 + 1;

    if (total_pixels < required_pixels) {
        printf("Error: Image too small to hold message\n");
        printf("Required pixels: %d, Available: %d\n", required_pixels, total_pixels);
        fclose(fp);
        return -1;
    }

    // Allocate memory for pixel data
    unsigned char *pixel_data = (unsigned char *)malloc(row_size * height);
    fread(pixel_data, row_size * height, 1, fp);
    fclose(fp);

    // Convert message to binary
    char *message_bits = (char *)malloc(total_bits + 1);
    int bit_idx = 0;

    for (int i = 0; i < msg_len; i++) {
        char binary[9];
        char_to_binary(message[i], binary);
        for (int j = 0; j < 8; j++) {
            message_bits[bit_idx++] = binary[j];
        }
    }
    // Add null terminator (8 zeros)
    for (int j = 0; j < 8; j++) {
        message_bits[bit_idx++] = '0';
    }

    // Embed bits into LSB of each color channel
    int embed_idx = 0;
    for (int y = 0; y < height && embed_idx < total_bits; y++) {
        for (int x = 0; x < width && embed_idx < total_bits; x++) {
            int pixel_offset = y * row_size + x * 3;

            // Embed in Red channel
            if (embed_idx < total_bits) {
                pixel_data[pixel_offset] = 
                    (pixel_data[pixel_offset] & 0xFE) | (message_bits[embed_idx] - '0');
                embed_idx++;
            }

            // Embed in Green channel
            if (embed_idx < total_bits) {
                pixel_data[pixel_offset + 1] = 
                    (pixel_data[pixel_offset + 1] & 0xFE) | (message_bits[embed_idx] - '0');
                embed_idx++;
            }

            // Embed in Blue channel
            if (embed_idx < total_bits) {
                pixel_data[pixel_offset + 2] = 
                    (pixel_data[pixel_offset + 2] & 0xFE) | (message_bits[embed_idx] - '0');
                embed_idx++;
            }
        }
    }

    // Write output file
    fp = fopen(output_path, "wb");
    if (!fp) {
        printf("Error: Cannot create output file\n");
        free(pixel_data);
        free(message_bits);
        return -1;
    }

    fwrite(&fileHeader, sizeof(BITMAPFILEHEADER), 1, fp);
    fwrite(&infoHeader, sizeof(BITMAPINFOHEADER), 1, fp);
    fwrite(pixel_data, row_size * height, 1, fp);
    fclose(fp);

    free(pixel_data);
    free(message_bits);

    printf("Message embedded successfully!\n");
    printf("Bits embedded: %d\n", embed_idx);
    return 0;
}

// Extract message from BMP file
int extract_message(const char *stego_path) {
    FILE *fp = fopen(stego_path, "rb");
    if (!fp) {
        printf("Error: Cannot open stego image\n");
        return -1;
    }

    // Read BMP headers
    BITMAPFILEHEADER fileHeader;
    BITMAPINFOHEADER infoHeader;

    fread(&fileHeader, sizeof(BITMAPFILEHEADER), 1, fp);
    fread(&infoHeader, sizeof(BITMAPINFOHEADER), 1, fp);

    int width = infoHeader.biWidth;
    int height = abs(infoHeader.biHeight);
    int row_size = ((width * 3 + 3) / 4) * 4;

    // Read pixel data
    unsigned char *pixel_data = (unsigned char *)malloc(row_size * height);
    fread(pixel_data, row_size * height, 1, fp);
    fclose(fp);

    // Extract bits
    char current_byte[9] = {0};
    char *extracted_message = (char *)malloc(256);
    int msg_idx = 0;
    int bit_position = 0;

    for (int y = 0; y < height; y++) {
        for (int x = 0; x < width; x++) {
            int pixel_offset = y * row_size + x * 3;

            // Extract from Red channel
            current_byte[bit_position++] = (pixel_data[pixel_offset] & 1) ? '1' : '0';
            if (bit_position == 8) {
                if (strcmp(current_byte, "00000000") == 0) {
                    extracted_message[msg_idx] = '\0';
                    printf("Extracted Message: %s\n", extracted_message);
                    free(pixel_data);
                    free(extracted_message);
                    return 0;
                }
                extracted_message[msg_idx++] = binary_to_char(current_byte);
                bit_position = 0;
            }

            // Extract from Green channel
            current_byte[bit_position++] = (pixel_data[pixel_offset + 1] & 1) ? '1' : '0';
            if (bit_position == 8) {
                if (strcmp(current_byte, "00000000") == 0) {
                    extracted_message[msg_idx] = '\0';
                    printf("Extracted Message: %s\n", extracted_message);
                    free(pixel_data);
                    free(extracted_message);
                    return 0;
                }
                extracted_message[msg_idx++] = binary_to_char(current_byte);
                bit_position = 0;
            }

            // Extract from Blue channel
            current_byte[bit_position++] = (pixel_data[pixel_offset + 2] & 1) ? '1' : '0';
            if (bit_position == 8) {
                if (strcmp(current_byte, "00000000") == 0) {
                    extracted_message[msg_idx] = '\0';
                    printf("Extracted Message: %s\n", extracted_message);
                    free(pixel_data);
                    free(extracted_message);
                    return 0;
                }
                extracted_message[msg_idx++] = binary_to_char(current_byte);
                bit_position = 0;
            }
        }
    }

    // No null terminator found, print what we have
    extracted_message[msg_idx] = '\0';
    printf("Extracted Message: %s\n", extracted_message);

    free(pixel_data);
    free(extracted_message);
    return 0;
}

int main(int argc, char *argv[]) {
    printf("=== LSB Image Steganography (C) ===\n\n");

    // Note: This requires a valid BMP file named 'carrier.bmp'
    // For demonstration, you would need to provide a test image

    if (argc < 2) {
        printf("Usage:\n");
        printf("  Embed: %s embed <carrier.bmp> "message" <output.bmp>\n", argv[0]);
        printf("  Extract: %s extract <stego.bmp>\n", argv[0]);
        return 1;
    }

    if (strcmp(argv[1], "embed") == 0 && argc >= 5) {
        embed_message(argv[2], argv[3], argv[4]);
    } else if (strcmp(argv[1], "extract") == 0 && argc >= 3) {
        extract_message(argv[2]);
    } else {
        printf("Invalid arguments\n");
    }

    return 0;
}
